namespace sv_1260b614fbaa49df9553e183a2c508f2.Services;

public class WizardData
{
    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<Reference> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using Microsoft.Extensions.Caching.Memory;

namespace sv_1260b614fbaa49df9553e183a2c508f2.Services;

/// <summary>
/// Singleton store for wizard data, keyed by session ID.
/// Uses IMemoryCache with sliding expiration so entries auto-expire.
/// </summary>
public class WizardStateStore
{
    private readonly IMemoryCache _cache;
    private static readonly TimeSpan Expiration = TimeSpan.FromMinutes(30);

    public WizardStateStore(IMemoryCache cache)
    {
        _cache = cache;
    }

    public WizardData GetOrCreate(string sessionId)
    {
        return _cache.GetOrCreate($"wizard_{sessionId}", entry =>
        {
            entry.SlidingExpiration = Expiration;
            return new WizardData();
        })!;
    }

    public void Save(string sessionId, WizardData data)
    {
        _cache.Set($"wizard_{sessionId}", data, new MemoryCacheEntryOptions
        {
            SlidingExpiration = Expiration
        });
    }
}

