﻿@inherits LayoutComponentBase
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_1260b614fbaa49df9553e183a2c508f2.Services.WizardStateStore WizardStore

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <div class="d-flex align-items-center gap-2 flex-grow-1">
                    <strong>Step @WizardProgress.CurrentStep of 4</strong>
                    @for (int i = 1; i <= 4; i++)
                    {
                        var stepClass = WizardProgress.CompletedSteps.Contains(i)
                            ? "bg-success"
                            : i == WizardProgress.CurrentStep
                                ? "bg-primary"
                                : "bg-secondary";
                        <div class="progress-step rounded @stepClass" style="width:40px;height:8px;"></div>
                    }
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private WizardData WizardProgress { get; set; } = new();
    private bool IsWizardPage;

    protected override void OnInitialized()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        IsWizardPage = path.StartsWith("/apply", StringComparison.OrdinalIgnoreCase);

        if (IsWizardPage)
        {
            var sessionId = HttpContextAccessor.HttpContext?.Session.Id;
            if (!string.IsNullOrEmpty(sessionId))
            {
                WizardProgress = WizardStore.GetOrCreate(sessionId);
            }
        }
    }
}

