@page "/apply/review"
@rendermode InteractiveServer
@inject WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@using sv_1260b614fbaa49df9553e183a2c508f2.Services

<PageTitle>Apply - Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Data.FullName</p>
    <p><strong>Email:</strong> @Data.Email</p>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (Data.JobHistory.Count == 0)
    {
        <p class="text-muted">No entries</p>
    }
    @foreach (var job in Data.JobHistory)
    {
        <p>@job.Title at @job.Company (@job.Duration)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Data.References.Count == 0)
    {
        <p class="text-muted">No entries</p>
    }
    @foreach (var r in Data.References)
    {
        <p>@r.Name — @r.Relationship (@r.Phone)</p>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private string _sessionId = "";
    private WizardData Data { get; set; } = new();

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (!string.IsNullOrEmpty(sessionId))
        {
            _sessionId = sessionId;
        }

        if (!string.IsNullOrEmpty(_sessionId))
        {
            Data = WizardStore.GetOrCreate(_sessionId);
            Data.CurrentStep = 4;
        }
    }

    private void Back()
    {
        WizardStore.Save(_sessionId, Data);
        Nav.NavigateTo("/apply/references");
    }

    private void Submit()
    {
        Data.CompletedSteps.Add(4);
        WizardStore.Save(_sessionId, Data);
        // In a real app: persist to database, send email, etc.
        Nav.NavigateTo("/");
    }
}

